async (params, browser) => {
  // Open profile
  await browser.open(`${params.profile_url}`)

  // Wait for profile
  await browser.waitForSelector('[class*=\'Profile\'], [class*=\'profile\'], h1', 15000)

  await browser.wait(2000)

  // Scroll for content
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract profile
  const profile_data = await browser.evaluate(`const nameEl = document.querySelector('[class*="profile-name"], [class*="ProfileName"], h1'); const bioEl = document.querySelector('[class*="profile-description"], [class*="bio"]'); const credentialEl = document.querySelector('[class*="credential"], [class*="ProfileCredential"]'); const followersEl = document.querySelector('[class*="followers"] [class*="count"], [class*="FollowerCount"]'); const answersCountEl = document.querySelector('[class*="answers"] [class*="count"], [class*="AnswerCount"]'); const avatarEl = document.querySelector('[class*="profile-photo"] img, [class*="avatar"] img'); const stats = {}; document.querySelectorAll('[class*="stat"], [class*="ProfileStat"]').forEach(function(el) { const text = el.textContent.trim(); if (text) { const parts = text.split('\n').filter(function(p) { return p.trim(); }); if (parts.length >= 2) stats[parts[1].trim()] = parts[0].trim(); } }); return { name: nameEl ? nameEl.textContent.trim() : '', bio: bioEl ? bioEl.textContent.trim().substring(0, 1000) : '', credential: credentialEl ? credentialEl.textContent.trim() : '', followers: followersEl ? followersEl.textContent.trim() : '', answers_count: answersCountEl ? answersCountEl.textContent.trim() : '', avatar: avatarEl ? avatarEl.getAttribute('src') : '', stats: stats, url: window.location.href }`)

  return profile_data
}
